import{_ as i,n as l,v as a,ac as s}from"./chunks/framework.DFVDdn94.js";const o="/blog/interview/browser/vite1.png",c="/blog/interview/browser/vite2.png",b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"interview/ba-gu/webpack.md","filePath":"interview/ba-gu/webpack.md","lastUpdated":1740995208000}'),d={name:"interview/ba-gu/webpack.md"};function t(n,e,p,r,k,u){return a(),l("div",null,e[0]||(e[0]=[s('<h2 id="webpack-中-loader-和-plugin-有什么不同" tabindex="-1">webpack 中 Loader 和 Plugin 有什么不同 <a class="header-anchor" href="#webpack-中-loader-和-plugin-有什么不同" aria-label="Permalink to &quot;webpack 中 Loader 和 Plugin 有什么不同&quot;">​</a></h2><p>Loader 直译为&quot;加载器&quot;。Webpack 将⼀切⽂件视为模块，但是 webpack 原⽣是只能解析 js ⽂件，如果想将其他⽂件也打包的话，就会⽤到 loader 。 所以 Loader 的作⽤是让 webpack 拥有了加载和解析⾮ JavaScript ⽂件的能⼒。</p><details class="details custom-block"><summary>常用的 loader</summary><ul><li>babel-loader 把 JS/TS 变成 JS</li><li>ts-loader 把 TS 变成 JS，并提示类型错误</li><li>markdown-loader 把 markdown 变成 html</li><li>html-loader 把 html 变成 JS 字符串</li><li>sass-loader 把 SASS/SCSS 变成 CSS</li><li>css-loader 把 CSS 变成 JS 字符串</li><li>style-loader 把 JS 字符串变成 style 标签</li><li>postcss-loader 把 CSS 变成更优化的 CSS</li><li>vue-loader 把单文件组件（SFC）变成 JS 模块</li><li>thread-loader 用于多进程打包</li><li>file-loader 解决图片引入问题，将图片 copy 到指定目录(默认 dist)</li><li>url-loader 将小于 limit 选项配置大小的图片转换为 base64 编码，大于 limit 选项配置大小的图片还是采用 file-loader</li></ul></details><p>Plugin 直译为&quot;插件&quot;。Plugin 可以扩展 webpack 的功能，让 webpack 具有更多的灵活性。在 Webpack 运⾏的⽣命周期中会⼴播出许多事 件，Plugin 可以监听这些事件，在合适的时机通过 Webpack 提供的 API 改变输出结果。</p><details class="details custom-block"><summary>常用的 plugin</summary><ul><li>html-webpack-plugin 用于创建 HTML 页面并自动引入 JS 和 CSS</li><li>clean-webpack-plugin 用于清理之前打包的残余文件</li><li>mini-css-extract-plugin 用于将 JS 中的 CSS 抽离成单独的 CSS 文件</li><li>SplitChunksPlugin 用于代码分包（Code Split）</li><li>DllPlugin + DllReferencePlugin 用于避免大依赖被频繁重新打包，大幅降低打包时间</li><li>eslint-webpack-plugin 用于检查代码中的错误</li><li>DefinePlugin 用于在 webpack config 里添加全局变量</li><li>copy-webpack-plugin 用于拷贝静态文件到 dist</li></ul></details><h2 id="webpack-中-bundle-chunk-module-是什么" tabindex="-1">webpack 中 bundle，chunk，module 是什么 <a class="header-anchor" href="#webpack-中-bundle-chunk-module-是什么" aria-label="Permalink to &quot;webpack 中 bundle，chunk，module 是什么&quot;">​</a></h2><ul><li>bundle：是由 webpack 打包出来的⽂件；</li><li>chunk：代码块，⼀个 chunk 由多个模块组合⽽成，⽤于代码的合并 和分割；</li><li>module：是开发中的单个模块，在 webpack 的世界，⼀切皆模块，⼀ 个模块对应⼀个⽂件，webpack 会从配置的 entry 中递归开始找出所 有依赖的模块。</li></ul><h2 id="webpack-的构建流程" tabindex="-1">webpack 的构建流程 <a class="header-anchor" href="#webpack-的构建流程" aria-label="Permalink to &quot;webpack 的构建流程&quot;">​</a></h2><ul><li>初始化参数：从配置文件和 Shell 语句中读取与合并参数，得出最终的参数；</li><li>开始编译：用上一步得到的参数初始化 Compiler 对象，加载所有配置的插件，执行对象的 run 方法开始执行编译；</li><li>确定入口：根据配置中的 entry 找出所有的入口文件；</li><li>编译模块：从入口文件出发，调用所有配置的 Loader 对模块进行翻译，再找出该模块依赖的模块，再递归本步骤直到所有入口依赖的文件都经过了本步骤的处理；</li><li>完成模块编译：在经过第 4 步使用 Loader 翻译完所有模块后，得到了每个模块被翻译后的最终内容以及它们之间的依赖关系；</li><li>输出资源：根据入口和模块之间的依赖关系，组装成一个个包含多个模块的 Chunk，再把每个 Chunk 转换成一个单独的文件加入到输出列表，这步是可以修改输出内容的最后机会；</li><li>输出完成：在确定好输出内容后，根据配置确定输出的路径和文件名，把文件内容写入到文件系统</li></ul><h2 id="webpack-层面如何性能优化" tabindex="-1">Webpack 层面如何性能优化？ <a class="header-anchor" href="#webpack-层面如何性能优化" aria-label="Permalink to &quot;Webpack 层面如何性能优化？&quot;">​</a></h2><p><strong>优化构建速度</strong></p><ul><li>构建费时分析 <code>speed-measure-webpack-plugin</code></li><li>构建进度查看：<code>progress-bar-webpack-plugin</code></li><li><code>resolve</code> 配置优化 <ul><li><code>alias</code> 别名，用来简化模块的引用</li><li><code>extensions</code> 当用户引入的文件不带后缀名，手动配置会覆盖默认配置。[&#39;.ts&#39;, &#39;...&#39;]，...表示采用默认配置</li><li><code>modules</code> 告诉 <code>webpack</code> 优先查找 src 目录中的文件，modules: [resolve(&#39;src&#39;), &#39;node_modules&#39;]</li></ul></li><li><code>externals</code> 剥离不需要改动的一些依赖(从输出的 bundle 中排除依赖)</li><li><code>loader</code> 中使用 include 解析符合条件的模块、exclude 排除(不解析)符合条件的模块，优先级高于 include</li><li><code>noParse</code> 不解析依赖的第三方类库等</li><li><code>IgnorePlugin</code> 防止在 import 或 require 调用时，生成 contextRegExp 指定资源不符合 requestRegExp 正则匹配的资源</li><li><code>thread-loader</code> 开启多进程打包，happypack webpack5 已经弃用了</li><li><code>babel-loader</code> 启用缓存，缓存结果，大幅提升重新构建 js 文件的速度</li><li><code>cache-loader</code> 缓存其他 loader 的构建结果</li><li><code>hard-source-webpack-plugin</code> 为模块提供中间缓存，重复构建时间大约可以减少 80%，但是在 webpack5 中已经内置了模块缓存，不需要再使用此插件</li><li><code>cache</code> 通过配置 cache 来缓存生成的 webpack 模块和 chunk，来改善构建速度</li></ul><p><strong>优化构建结果</strong></p><ul><li>webpack-bundle-analyzer 对构建结果分析</li><li>optimize-css-assets-webpack-plugin 压缩 css 文件</li><li>terser-webpack-plugin 压缩 js 文件，在生成环境下打包默认会开启 js 压缩，但是当我们手动配置 optimization 选项之后，就不再默认对 js 进行压缩，需要我们手动去配置</li><li>purgecss-webpack-plugin 单独提取 css 文件并清除用不到的 css</li><li>Tree-shaking 剔除没有使用的代码，webpack 默认支持，需要在 .bablerc 里面设置 model：false，即可在生产环境下默认开启</li><li>Scope Hoisting Scope Hoisting 即作用域提升，原理是将多个模块放在同一个作用域下，并重命名防止命名冲突，通过这种方式可以减少函数声明和内存开销，只支持 es6 语法，生产环境默认开启</li></ul><p><strong>优化运行时体验</strong></p><ul><li>入口点分割：配置多个打包入口，多页打包</li><li>splitChunks 分包配置，webpack 将根据以下条件自动拆分 chunks： <ul><li>新的 chunk 可以被共享，或者模块来自于 node_modules 文件夹</li><li>新的 chunk 体积大于 20kb（在进行 min+gz 之前的体积）</li><li>当按需加载 chunks 时，并行请求的最大数量小于或等于 30</li><li>当加载初始化页面时，并发请求的最大数量小于或等于 30</li></ul></li><li>代码懒加载：当有需要用户交互后才加载的资源时，可以当用户操作后，引入资源 <ul><li>webpackprefetch (预获取)：浏览器空闲的时候进行资源的拉取</li><li>webpackpreload (预加载)：提前加载后面会用到的关键资源</li></ul></li></ul><h2 id="vite-为什么这么快-快在了哪里" tabindex="-1">vite 为什么这么快，快在了哪里 <a class="header-anchor" href="#vite-为什么这么快-快在了哪里" aria-label="Permalink to &quot;vite 为什么这么快，快在了哪里&quot;">​</a></h2><ul><li>项目启动快</li></ul><p>Vite 在打包的时候，将模块分成两个区域 <strong>依赖</strong> 和 <strong>源码</strong> ：</p><p><strong>依赖</strong> ：一般是那种在开发中不会改变的 <code>JavaScript</code>，比如组件库，或者一些较大的依赖（可能有上百个模块的库），这一部分使用 <code>esbuild</code> 来进行 预构建依赖 , <code>esbuild</code> 使用的是 <code>Go</code> 进行编写，比 <code>JavaScript</code> 编写的打包器预构建依赖快 10-100 倍</p><p><strong>源码</strong> ：一般是哪种好修改几率比较大的文件，例如 <code>JSX、CSS、vue</code> 这些需要转换且时常会被修改编辑的文件。同时，这些文件并不是一股脑全部加载，而是可以按需加载（例如路由懒加载）。 <code>Vite</code> 会将文件转换后，以 <code>es module</code> 的方式直接交给浏览器，因为现在的浏览器大多数都直接支持 <code>es module</code> ，这使性能提高了很多</p><p>Vite 是直接把转换后的 es module 的 JavaScript 代码，扔给 支持 es module 的浏览器 ，让浏览器自己去加载依赖，也就是把压力丢给了 浏览器 ，从而达到了项目启动速度快的效果。</p><p><img src="'+o+'" alt="vite1"></p><ul><li>项目更新快</li></ul><p>项目启动时，将模块分成 <strong>依赖</strong> 和 <strong>源码</strong> ，当你更新代码时， <strong>依赖</strong> 就不需要重新加载，只需要精准地找到是哪个 <strong>源码</strong> 的文件更新了，更新相对应的文件就行了。这样做使得更新速度非常快。</p><p><code>Vite</code> 同时利用 <code>HTTP</code> 头来加速整个页面的重新加载（再次让浏览器为我们做更多事情）：</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>源码模块的请求会根据 <code>304 Not Modified</code> 进行协商缓存。</p><p>而依赖模块请求则会通过 <code>Cache-Control: max-age=31536000</code>, <code>immutable</code> 进行强缓存，因此一旦被缓存它们将不需要再次请求。</p></div><ul><li>生产环境快</li></ul><p>为了在生产环境中获得最佳的加载性能，使用了 <code>rollup</code> 将代码进行 <code>tree-shaking</code>、懒加载和 <code>chunk</code> 分割、CSS 处理，这些优化操作，目前 <code>esbuild</code> 还不怎么完善</p><h2 id="vite-与-webpack-对比" tabindex="-1">vite 与 webpack 对比 <a class="header-anchor" href="#vite-与-webpack-对比" aria-label="Permalink to &quot;vite 与 webpack 对比&quot;">​</a></h2><p>由于 <code>Vite</code> 主打的是开发环境的极致体验，生产环境集成 <code>Rollup</code>，这里的对比主要是 <code>Webpack-dev-server</code> 与 <code>Vite-dev-server</code> 的对比：</p><ul><li><code>Webpack</code> 配置丰富使用极为灵活但上手成本高，<code>Vite</code> 开箱即用配置高度集成</li><li><code>Webpack</code> 启动服务需打包构建，速度慢，<code>Vite</code> 免编译可秒开</li><li><code>Webpack</code> 热更新需打包构建，速度慢，<code>Vite</code> 毫秒响应</li><li><code>Webpack</code> 成熟稳定、资源丰富、大量实践案例，<code>Vite</code> 实践较少</li><li><code>Vite</code> 使用 <code>esbuild</code> 编译，构建速度比 <code>webpack</code> 快几个数量级</li></ul><h2 id="vite-双引擎架构实现" tabindex="-1">Vite 双引擎架构实现 <a class="header-anchor" href="#vite-双引擎架构实现" aria-label="Permalink to &quot;Vite 双引擎架构实现&quot;">​</a></h2><p><img src="'+c+`" alt="vite2"></p><ul><li><p>开发阶段：<code>ESBuild</code> 依赖预构建 主要是 ESM 格式的兼容性问题和海量请求的问题</p></li><li><p>单文件编译——作为 <code>TS</code> 和 <code>JSX</code> 编译工具 <code>ESBuild</code> 代替 <code>bable</code> 的工作，对代码进行 <code>transformer</code></p></li><li><p>生产环境 <code>ESBuild</code> 代码压缩</p></li><li><p>生产环境 <code>Bundle</code> 基于 <code>Rollup</code></p><ol><li><code>CSS</code> 代码分割。如果某个异步模块中引入了一些 <code>CSS</code> 代码，<code>Vite</code> 就会自动将这些 CSS 抽取出来生成单独的文件，提高线上产物的缓存复用率。</li><li>自动预加载。<code>Vite</code> 会自动为入口 chunk 的依赖自动生成预加载标签 <code>&lt;link rel=&quot;moduelpreload&quot;&gt;</code> 会让浏览器提前下载好资源，优化页面性能，如:</li></ol><div class="language-html vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-dark-default github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#E6EDF3;--shiki-light:#24292E;">&lt;</span><span style="--shiki-dark:#7EE787;--shiki-light:#22863A;">head</span><span style="--shiki-dark:#E6EDF3;--shiki-light:#24292E;">&gt;</span></span>
<span class="line"><span style="--shiki-dark:#8B949E;--shiki-light:#6A737D;">  &lt;!-- 省略其它内容 --&gt;</span></span>
<span class="line"><span style="--shiki-dark:#8B949E;--shiki-light:#6A737D;">  &lt;!-- 入口 chunk --&gt;</span></span>
<span class="line"><span style="--shiki-dark:#E6EDF3;--shiki-light:#24292E;">  &lt;</span><span style="--shiki-dark:#7EE787;--shiki-light:#22863A;">script</span><span style="--shiki-dark:#79C0FF;--shiki-light:#6F42C1;"> type</span><span style="--shiki-dark:#E6EDF3;--shiki-light:#24292E;">=</span><span style="--shiki-dark:#A5D6FF;--shiki-light:#032F62;">&quot;module&quot;</span><span style="--shiki-dark:#79C0FF;--shiki-light:#6F42C1;"> crossorigin</span><span style="--shiki-dark:#79C0FF;--shiki-light:#6F42C1;"> src</span><span style="--shiki-dark:#E6EDF3;--shiki-light:#24292E;">=</span><span style="--shiki-dark:#A5D6FF;--shiki-light:#032F62;">&quot;/assets/index.250e0340.js&quot;</span><span style="--shiki-dark:#E6EDF3;--shiki-light:#24292E;">&gt;&lt;/</span><span style="--shiki-dark:#7EE787;--shiki-light:#22863A;">script</span><span style="--shiki-dark:#E6EDF3;--shiki-light:#24292E;">&gt;</span></span>
<span class="line"><span style="--shiki-dark:#8B949E;--shiki-light:#6A737D;">  &lt;!--  自动预加载入口 chunk 所依赖的 chunk--&gt;</span></span>
<span class="line"><span style="--shiki-dark:#E6EDF3;--shiki-light:#24292E;">  &lt;</span><span style="--shiki-dark:#7EE787;--shiki-light:#22863A;">link</span><span style="--shiki-dark:#79C0FF;--shiki-light:#6F42C1;"> rel</span><span style="--shiki-dark:#E6EDF3;--shiki-light:#24292E;">=</span><span style="--shiki-dark:#A5D6FF;--shiki-light:#032F62;">&quot;modulepreload&quot;</span><span style="--shiki-dark:#79C0FF;--shiki-light:#6F42C1;"> href</span><span style="--shiki-dark:#E6EDF3;--shiki-light:#24292E;">=</span><span style="--shiki-dark:#A5D6FF;--shiki-light:#032F62;">&quot;/assets/vendor.293dca09.js&quot;</span><span style="--shiki-dark:#E6EDF3;--shiki-light:#24292E;"> /&gt;</span></span>
<span class="line"><span style="--shiki-dark:#E6EDF3;--shiki-light:#24292E;">&lt;/</span><span style="--shiki-dark:#7EE787;--shiki-light:#22863A;">head</span><span style="--shiki-dark:#E6EDF3;--shiki-light:#24292E;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><ol start="3"><li>异步 <code>Chunk</code> 加载优化 如现有两个异步引入的 <code>Chunk</code>: A 和 B，而且两者有一个公共依赖 C</li></ol><p>一般情况下，<code>Rollup</code> 打包之后，会先请求 A，然后浏览器在加载 A 的过程中才决定请求和加载 C</p><p>但 <code>Vite</code> 进行优化之后，请求 A 的同时会自动预加载 C，通过优化 Rollup 产物依赖加载方式节省了不必要的网络开销。</p></li></ul><h2 id="vite-预构建主要做了些什么" tabindex="-1">vite 预构建主要做了些什么 <a class="header-anchor" href="#vite-预构建主要做了些什么" aria-label="Permalink to &quot;vite 预构建主要做了些什么&quot;">​</a></h2><p>Vite 中的依赖预构建技术主要解决了 2 个问题，即模块格式兼容问题和海量模块请求的问题。</p>`,37)]))}const g=i(d,[["render",t]]);export{b as __pageData,g as default};
